\section{$\Module\,k$-finite transport companions for the $H^0$ bridges (iter-038)}
\label{sec:HModule_finite_zero_iter038}

After Definitions~\ref{def:Scheme_HModule_zero_linearEquiv} and~\ref{def:Scheme_HModule_prime_zero_linearEquiv} the iteration~010/015 $H^0$ bridges identify $\HModule\,k\,F\,0$ and $\HModulePrime\,k\,F\,0\,X$ with $k$-linear Hom groups. The iteration~038 companions package the immediate $\Module\,k$-finite transport: from finiteness of the Hom group, finiteness of the cohomology group follows by Mathlib's \lstinline{Module.Finite.equiv} (\lstinline{Mathlib/RingTheory/Finiteness/Basic.lean}). They mirror iteration~037's \lstinline{module_finite_HModule_of_HModule'_X₄} pattern (which performs the analogous transport across the iteration~035 corner-bridge, at general degree $n$ rather than degree $0$).

\begin{theorem}[$\Module\,k$-finite transport for $\HModule\,k\,F\,0$]
  \label{thm:Scheme_module_finite_HModule_zero}
  \lean{AlgebraicGeometry.Scheme.module_finite_HModule_zero}
  \uses{def:Scheme_HModule_zero_linearEquiv}
  Let $k$ be a field, $C$ a small category, $J$ a Grothendieck topology on $C$ with $\HasSheafify\,J\,(\ModuleCat.\{u\}\,k)$ and $\HasExt(\Sheaf(J, \ModuleCat.\{u\}\,k))$. For $F : \Sheaf(J, \ModuleCat.\{u\}\,k)$ such that the $k$-linear Hom group $((\mathtt{constantSheaf}\,J\,(\ModuleCat\,k)).\mathrm{obj}\,(\ModuleCat.\mathrm{of}\,k\,k) \to F)$ is $\Module.\mathrm{Finite}$ over $k$, the cohomology group $\HModule\,k\,F\,0$ is also $\Module.\mathrm{Finite}$ over $k$.
\end{theorem}

\begin{proof}
  \uses{def:Scheme_HModule_zero_linearEquiv}
  Direct application of \lstinline{Module.Finite.equiv} to the symmetric form of the iteration~010 $H^0$ bridge. Mathlib's \lstinline{Module.Finite.equiv} consumes a $k$-linear equivalence $M \simeq_k N$ together with $[\Module.\mathrm{Finite}\,k\,M]$ and produces $[\Module.\mathrm{Finite}\,k\,N]$. Applied to $(\mathtt{HModule\_zero\_linearEquiv}\,k\,F).\mathtt{symm} : ((\mathtt{constantSheaf}\,J\,\_).\mathrm{obj}\,(\ModuleCat.\mathrm{of}\,k\,k) \to F) \simeq_k \HModule\,k\,F\,0$, the Hom-group hypothesis on the LHS transports to the cohomology-group conclusion on the RHS. One-liner term-mode body \lstinline{Module.Finite.equiv (HModule_zero_linearEquiv k F).symm}.
\end{proof}

\begin{theorem}[$\Module\,k$-finite transport for $\HModulePrime\,k\,F\,0\,X$]
  \label{thm:Scheme_module_finite_HModule_prime_zero}
  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_zero}
  \uses{def:Scheme_HModule_prime_zero_linearEquiv}
  Let $k$ be a field, $C$ a small category, $J$ a Grothendieck topology on $C$ with $\HasWeakSheafify\,J\,(\mathrm{Type}\,u)$, $\HasSheafify\,J\,(\ModuleCat.\{u\}\,k)$, and $\HasExt(\Sheaf(J, \ModuleCat.\{u\}\,k))$. For $F : \Sheaf(J, \ModuleCat.\{u\}\,k)$ and $X : C$ such that the $k$-linear Hom group $((\mathtt{presheafToSheaf}\,J\,\_).\mathrm{obj}\,((\yoneda \circ \free_k).\mathrm{obj}\,X) \to F)$ is $\Module.\mathrm{Finite}$ over $k$, the cohomology group $\HModulePrime\,k\,F\,0\,X$ is also $\Module.\mathrm{Finite}$ over $k$.
\end{theorem}

\begin{proof}
  \uses{def:Scheme_HModule_prime_zero_linearEquiv}
  Direct application of \lstinline{Module.Finite.equiv} to $(\mathtt{HModulePrime\_zero\_linearEquiv}\,k\,F\,X).\mathtt{symm}$, parallel to Theorem~\ref{thm:Scheme_module_finite_HModule_zero}. One-liner term-mode body \lstinline{Module.Finite.equiv (HModule'_zero_linearEquiv k F X).symm}.
\end{proof}

\begin{remark}[Use in Serre finiteness]
  Together with iteration~037's \lstinline{module_finite_HModule_of_HModule'_X₄} (the analogue at general degree $n$ via the corner-bridge), the project now has the complete algebraic-to-cohomological $\Module.\mathrm{Finite}$ transport infrastructure at degree $0$ (no Mayer-Vietoris LES required) and at any degree via the corner-bridge (Mayer-Vietoris LES required for the geometric inputs). The substantive geometric inputs (Serre vanishing on affines, finiteness of the Hom-from-constant-sheaf for proper schemes) remain queued for iter-039+.
\end{remark}

